import{c as o,Q as i,j as t,m as l}from"./chunks/framework.j5cTrcw1.js";const u=JSON.parse('{"title":"Sagit-chu/flvx Merge Candidate List","description":"","frontmatter":{},"headers":[],"relativePath":"upstream-flvx-merge-candidates.md","filePath":"upstream-flvx-merge-candidates.md"}'),a={name:"upstream-flvx-merge-candidates.md"};function n(d,e,r,c,s,p){return i(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="sagit-chu-flvx-merge-candidate-list" tabindex="-1">Sagit-chu/flvx Merge Candidate List <a class="header-anchor" href="#sagit-chu-flvx-merge-candidate-list" aria-label="Permalink to &quot;Sagit-chu/flvx Merge Candidate List&quot;">​</a></h1><p>Source repository: <code>D:\\Data\\RSSQ\\flvx</code> (<code>Sagit-chu/flvx</code>, commit <code>6e249a5</code>)</p><p>Target repository: <code>D:\\Data\\RSSQ\\flvxt2</code> (<code>iKeilo/FLVXR2</code>, commit <code>e6633a49</code>)</p><p>Comparison summary:</p><ul><li>Common files: 805</li><li>Same content: 597</li><li>Same path but changed: 208</li><li>Upstream-only files: 196</li><li>Target-only files: 202</li></ul><p>This list is scoped to files that matter for runtime behavior, security, installation, backend APIs, agent behavior, and frontend product surfaces. Generated docs assets and historical planning notes are intentionally excluded unless they affect implementation.</p><h2 id="implementation-status" tabindex="-1">Implementation Status <a class="header-anchor" href="#implementation-status" aria-label="Permalink to &quot;Implementation Status&quot;">​</a></h2><p>Started in this branch:</p><ul><li>Panel Peering provider capability handshake now returns <code>providerType</code>, <code>protocolVersion</code>, feature flags, runtime modes, and explicit WG/TLS support flags.</li><li>Imported legacy providers without capability fields are normalized as <code>sagit-chu-compatible</code> baseline providers.</li><li>Remote shared node metadata is persisted in <code>remote_config</code> and shown in the Panel Sharing remote-usage cards.</li><li>Remote shared nodes are blocked from local-only node deployment and WG Path creation/update.</li><li>The WG Path frontend selector filters out remote shared nodes.</li><li>Upstream SSRF-oriented remote address safety helpers have been migrated into <code>security_utils.go</code>.</li><li>Panel Peering management endpoints are explicitly admin-only: share list/create/update/delete/reset, remote usage list, and remote node import.</li><li>Remote node import now validates URL shape, limits schemes to <code>http</code>/<code>https</code>, and rejects loopback/private/link-local/unspecified remote hosts.</li><li>Panel Sharing frontend now shows an unavailable state for non-admin users instead of calling protected APIs.</li><li>Compatibility and permission tests cover baseline provider normalization, capability parsing, remote import admin gating, and restricted URL rejection.</li></ul><p>Still pending:</p><ul><li>Importing the remaining upstream safety/test files and adapting their fixtures to FLVX commercial auth, HttpOnly cookie auth, WG, TLS templates, and shop schema.</li><li>Optional deeper Sagit-chu share-link parsing if their UI exposes non-URL token formats beyond the current remote URL + token import flow.</li><li>UI-level capability gating for any future provider that advertises extended WG/TLS support.</li><li>Optional admin allowlist for private Panel Peering targets if private-network panel sharing is required in controlled deployments.</li></ul><h2 id="directly-migratable" tabindex="-1">Directly Migratable <a class="header-anchor" href="#directly-migratable" aria-label="Permalink to &quot;Directly Migratable&quot;">​</a></h2><p>These files are absent from <code>flvxt2</code> or are mostly additive test/utility files. They can usually be copied first, then compiled to reveal any small dependency gaps.</p><h3 id="backend-tests-and-safety-coverage" tabindex="-1">Backend Tests And Safety Coverage <a class="header-anchor" href="#backend-tests-and-safety-coverage" aria-label="Permalink to &quot;Backend Tests And Safety Coverage&quot;">​</a></h3><ul><li><code>go-backend/internal/http/handler/config_access_test.go</code></li><li><code>go-backend/internal/http/handler/flow_upload_batch_test.go</code></li><li><code>go-backend/internal/http/handler/forward_proxy_protocol_test.go</code></li><li><code>go-backend/internal/http/handler/nftables_runtime_test.go</code></li><li><code>go-backend/internal/http/handler/system_upgrade_test.go</code></li><li><code>go-backend/internal/http/handler/tunnel_best_exit_test.go</code></li><li><code>go-backend/internal/http/handler/tunnel_probe_target_api_test.go</code></li><li><code>go-backend/internal/http/handler/tunnel_probe_target_test.go</code></li><li><code>go-backend/internal/http/handler/tunnel_quality_prober_test.go</code></li><li><code>go-backend/internal/http/handler/upgrade_test.go</code></li><li><code>go-backend/internal/http/middleware/auth_test.go</code></li><li><code>go-backend/internal/store/repo/config_policy_test.go</code></li><li><code>go-backend/internal/store/repo/repository_auth_test.go</code></li><li><code>go-backend/internal/store/repo/repository_backup_test.go</code></li><li><code>go-backend/internal/store/repo/repository_flow_batch_test.go</code></li><li><code>go-backend/internal/store/repo/repository_forward_proxy_protocol_test.go</code></li><li><code>go-backend/internal/store/repo/repository_nftables_test.go</code></li><li><code>go-backend/internal/store/repo/repository_storage_test.go</code></li><li><code>go-backend/internal/ws/server_test.go</code></li><li><code>go-backend/tests/contract/flow_upload_batch_contract_test.go</code></li><li><code>go-backend/tests/contract/forward_local_remote_addr_contract_test.go</code></li><li><code>go-backend/tests/contract/max_conn_limit_contract_test.go</code></li><li><code>go-backend/tests/contract/per_ip_speed_limit_contract_test.go</code></li><li><code>go-backend/tests/contract/storage_contract_test.go</code></li><li><code>go-backend/tests/contract/user_list_max_conn_contract_test.go</code></li></ul><p>Notes:</p><ul><li>Some tests may need fixture updates because <code>flvxt2</code> has commercial license checks, HttpOnly cookie auth, WG mode, TLS templates, and shop-related schema changes.</li><li>These are still valuable because they define expected behavior and catch regressions.</li></ul><h3 id="backend-utility-modules" tabindex="-1">Backend Utility Modules <a class="header-anchor" href="#backend-utility-modules" aria-label="Permalink to &quot;Backend Utility Modules&quot;">​</a></h3><ul><li><code>go-backend/internal/http/handler/security_utils.go</code> - migrated in this branch</li><li><code>go-backend/internal/security/password.go</code></li><li><code>go-backend/internal/security/password_test.go</code></li><li><code>go-backend/internal/auth/user_state.go</code></li></ul><p>Notes:</p><ul><li>These are low-risk if symbols do not conflict.</li><li><code>password.go</code> should be checked against current login/register logic before replacing any existing hash behavior.</li></ul><h3 id="repository-helpers" tabindex="-1">Repository Helpers <a class="header-anchor" href="#repository-helpers" aria-label="Permalink to &quot;Repository Helpers&quot;">​</a></h3><ul><li><code>go-backend/internal/store/repo/config_policy.go</code></li><li><code>go-backend/internal/store/repo/repository_auth.go</code></li><li><code>go-backend/internal/store/repo/repository_backup_test.go</code></li><li><code>go-backend/internal/store/repo/repository_pool_test.go</code></li><li><code>go-backend/internal/store/repo/repository_storage.go</code></li></ul><p>Notes:</p><ul><li>Additive repository methods are good candidates.</li><li>Do not overwrite <code>repository.go</code>, <code>repository_mutations.go</code>, or <code>model.go</code> blindly because <code>flvxt2</code> has extra commercial, deployment, TLS, WG, and payment tables.</li></ul><h3 id="gost-agent-tests" tabindex="-1">GOST/Agent Tests <a class="header-anchor" href="#gost-agent-tests" aria-label="Permalink to &quot;GOST/Agent Tests&quot;">​</a></h3><ul><li><code>go-gost/x/config/parsing/service/composite_limiter_test.go</code></li><li><code>go-gost/x/config/persist_test.go</code></li><li><code>go-gost/x/handler/forward/local/proxy_protocol_test.go</code></li><li><code>go-gost/x/limiter/conn/conn_test.go</code></li><li><code>go-gost/x/limiter/traffic/traffic_test.go</code></li><li><code>go-gost/x/listener/udp/listener_test.go</code></li><li><code>go-gost/x/registry/chain_test.go</code></li><li><code>go-gost/x/service/global_traffic_manager_test.go</code></li><li><code>go-gost/x/socket/chain_test.go</code></li><li><code>go-gost/x/socket/limiter_test.go</code></li><li><code>go-gost/x/socket/service_test.go</code></li></ul><p>Notes:</p><ul><li>Prefer importing tests first, then selectively port production changes only where tests fail.</li></ul><h2 id="needs-adaptation" tabindex="-1">Needs Adaptation <a class="header-anchor" href="#needs-adaptation" aria-label="Permalink to &quot;Needs Adaptation&quot;">​</a></h2><p>These files contain useful upstream behavior, but they overlap with <code>flvxt2</code> business changes or runtime design. They must be merged manually.</p><h3 id="nftables-runtime" tabindex="-1">nftables Runtime <a class="header-anchor" href="#nftables-runtime" aria-label="Permalink to &quot;nftables Runtime&quot;">​</a></h3><ul><li><code>go-backend/internal/http/handler/nftables_runtime.go</code></li><li><code>go-backend/internal/runtime/nftables/manager.go</code></li><li><code>go-backend/internal/runtime/nftables/parser.go</code></li><li><code>go-backend/internal/runtime/nftables/renderer.go</code></li><li><code>go-backend/internal/runtime/nftables/runner.go</code></li><li><code>go-backend/internal/runtime/nftables/types.go</code></li><li><code>go-backend/internal/store/repo/repository_nftables.go</code></li></ul><p>Why adaptation is needed:</p><ul><li>Upstream uses a backend-managed nftables runtime path with SSH reconciliation.</li><li><code>flvxt2</code> already has agent/socket based nftables and WG Path deployment logic in <code>go-gost/x/socket/nftables_handler.go</code>, <code>go-gost/x/socket/wireguard_handler.go</code>, and <code>go-backend/internal/http/handler/wg_path.go</code>.</li><li>A direct copy could create two independent nftables control planes.</li></ul><p>Recommended merge strategy:</p><ul><li>Extract upstream parser/renderer/runner as a reusable runtime package.</li><li>Wire it behind the existing <code>flvxt2</code> node deployment/diagnosis flow.</li><li>Keep WG Path authority in <code>wg_path.go</code>.</li><li>Add an explicit runtime mode boundary: <code>agent_socket</code>, <code>backend_ssh</code>, <code>wg_path</code>.</li></ul><h3 id="tunnel-probe-and-best-exit" tabindex="-1">Tunnel Probe And Best Exit <a class="header-anchor" href="#tunnel-probe-and-best-exit" aria-label="Permalink to &quot;Tunnel Probe And Best Exit&quot;">​</a></h3><ul><li><code>go-backend/internal/http/handler/tunnel_probe_target.go</code></li><li><code>go-backend/internal/http/handler/tunnel_best_exit.go</code></li><li><code>go-backend/internal/http/handler/tunnel_best_exit_display.go</code></li><li><code>go-backend/internal/http/handler/tunnel_quality_prober.go</code></li><li><code>go-backend/internal/store/repo/repository_tunnel_quality.go</code></li><li><code>vite-frontend/src/pages/tunnel.tsx</code></li><li><code>vite-frontend/src/pages/tunnel/diagnosis.ts</code></li><li><code>vite-frontend/src/pages/tunnel/form.ts</code></li></ul><p>Why adaptation is needed:</p><ul><li><code>flvxt2</code> has WG Path, commercial gating, revised UI, and tunnel grouping changes.</li><li>Upstream quality probing is valuable for NAT/WG fallback decisions, but UI and schema must fit the current tunnel manager.</li></ul><p>Recommended merge strategy:</p><ul><li>Port backend scoring/probe logic first.</li><li>Expose it to WG Path as optional diagnostics.</li><li>Merge frontend display only after API payloads stabilize.</li></ul><h3 id="forward-management" tabindex="-1">Forward Management <a class="header-anchor" href="#forward-management" aria-label="Permalink to &quot;Forward Management&quot;">​</a></h3><ul><li><code>go-backend/internal/http/handler/mutations.go</code></li><li><code>go-backend/internal/http/handler/user_quota.go</code></li><li><code>go-backend/internal/store/repo/repository_mutations.go</code></li><li><code>go-backend/internal/store/repo/repository_user_quota.go</code></li><li><code>vite-frontend/src/pages/forward.tsx</code></li><li><code>vite-frontend/src/pages/forward/batch-actions.ts</code></li><li><code>vite-frontend/src/pages/forward/order.ts</code></li><li><code>vite-frontend/src/api/types.ts</code></li></ul><p>Why adaptation is needed:</p><ul><li>Upstream supports <code>agent | nftables</code>.</li><li><code>flvxt2</code> supports <code>gost | nftables | wg_path</code> with admin-only WG restrictions.</li><li>Direct copy would likely remove WG Path rule creation and ordinary-user filtering.</li></ul><p>Recommended merge strategy:</p><ul><li>Diff only the specific upstream fixes: local/remote address validation, proxy protocol, stale runtime cleanup, port occupancy, failure detail handling.</li><li>Preserve <code>wg_path</code> branches and admin checks.</li></ul><h3 id="panel-peering-面板共享" tabindex="-1">Panel Peering / 面板共享 <a class="header-anchor" href="#panel-peering-面板共享" aria-label="Permalink to &quot;Panel Peering / 面板共享&quot;">​</a></h3><ul><li><code>go-backend/internal/http/handler/federation.go</code></li><li><code>go-backend/internal/http/client/federation.go</code></li><li><code>go-backend/internal/store/repo/repository_federation.go</code></li><li><code>go-backend/internal/store/model/model.go</code> peer-sharing structs</li><li><code>go-backend/internal/http/handler/mutations.go</code> federation runtime binding sections</li><li><code>go-backend/internal/http/handler/flow_policy.go</code></li><li><code>go-backend/internal/http/handler/flow_policy_federation_test.go</code></li><li><code>go-backend/tests/contract/federation_dual_panel_contract_test.go</code></li><li><code>go-backend/tests/contract/federation_forward_flow_linkage_contract_test.go</code></li><li><code>vite-frontend/src/pages/panel-sharing.tsx</code></li><li><code>vite-frontend/src/api/index.ts</code> federation API section</li><li><code>vite-frontend/src/layouts/admin.tsx</code> navigation entry</li></ul><p>Why adaptation is needed:</p><ul><li>Both repositories already implement a federation-style panel sharing model, but <code>flvxt2</code> has extra commercial licensing, HttpOnly Cookie browser auth, WG Path, TLS/inbound deployment, and product visibility rules.</li><li>Upstream <code>Sagit-chu/flvx</code> currently provides the useful compatibility target because it exposes the same family of endpoints: <ul><li><code>/api/v1/federation/share/list</code></li><li><code>/api/v1/federation/share/create</code></li><li><code>/api/v1/federation/share/update</code></li><li><code>/api/v1/federation/share/delete</code></li><li><code>/api/v1/federation/share/reset-flow</code></li><li><code>/api/v1/federation/share/remote-usage/list</code></li><li><code>/api/v1/federation/connect</code></li><li><code>/api/v1/federation/tunnel/create</code></li><li><code>/api/v1/federation/runtime/reserve-port</code></li><li><code>/api/v1/federation/runtime/apply-role</code></li><li><code>/api/v1/federation/runtime/release-role</code></li><li><code>/api/v1/federation/runtime/diagnose</code></li><li><code>/api/v1/federation/runtime/command</code></li><li><code>/api/v1/federation/node/import</code></li></ul></li><li>Direct replacement is unsafe because <code>flvxt2</code> has already moved more logic into commercial boundaries and has additional node metadata such as deployment identity, TLS templates, and WG-related behavior.</li></ul><p>Compatibility behavior to preserve or add:</p><ol><li><p>Provider side creates a share:</p><ul><li>Admin chooses local node, name, bandwidth limit, flow limit, port range, expiry, allowed domains, and allowed IPs.</li><li>Backend creates or updates <code>peer_share</code>.</li><li>Backend returns a share URI containing at least <code>remote_url</code> and <code>token</code>.</li><li>Share token must stay compatible with Sagit-chu import flow.</li></ul></li><li><p>Consumer side imports a share:</p><ul><li>User pastes a Sagit-chu-compatible share URI or manually enters <code>remote_url + token</code>.</li><li><code>flvxt2</code> calls provider <code>/api/v1/federation/connect</code>.</li><li>If response is old/upstream format, normalize it into the current <code>flvxt2</code> remote node schema.</li><li>Imported node is stored as a remote/federated node, not as a normal locally managed deployment node.</li><li>Imported node must not expose local-only actions such as node deploy, TLS deployment, WG Path install, or core config push.</li></ul></li><li><p>Runtime reservation:</p><ul><li>When a tunnel uses a remote federated node, <code>flvxt2</code> calls <code>/runtime/reserve-port</code> on the provider.</li><li>Request must include local domain, resource key, tunnel role, desired protocol, strategy, and requested port when available.</li><li>If provider is Sagit-chu and does not know newer fields, omit unknown fields or tolerate ignored fields.</li><li>Store the returned allocation in <code>federation_tunnel_binding</code>.</li></ul></li><li><p>Runtime apply:</p><ul><li>After reservation, call <code>/runtime/apply-role</code>.</li><li>Role should be one of <code>entry</code>, <code>middle</code>, <code>exit</code>, or <code>forward</code>.</li><li>For Sagit-chu compatibility, use GOST/nftables-compatible tunnel runtime payloads only.</li><li>Do not send <code>wg_path</code>, S-UI inbound templates, Reality TLS templates, or sing-box-only configs to an upstream Sagit-chu provider unless a capability handshake says it supports them.</li></ul></li><li><p>Runtime release:</p><ul><li>On tunnel update/delete/failure rollback, call <code>/runtime/release-role</code>.</li><li>Release must be best effort but must also mark local <code>federation_tunnel_binding</code> status inactive.</li><li>Release by <code>resource_key</code> first, fallback to <code>binding_id</code> or allocated port for older provider behavior.</li></ul></li><li><p>Flow accounting:</p><ul><li>Keep local display flow compatible with upstream <code>peer_share.current_flow</code>.</li><li>Merge flow from: <ul><li>provider-side share usage</li><li>local tunnel/forward usage linked through <code>federation_tunnel_binding</code></li><li>remote usage list from <code>/share/remote-usage/list</code></li></ul></li><li>When remote provider lacks detailed per-runtime usage, fall back to share-level flow split by active bindings, matching current upstream contract tests.</li></ul></li><li><p>Diagnostics:</p><ul><li>For remote federated nodes, tunnel/forward diagnosis should proxy to <code>/runtime/diagnose</code>.</li><li>UI should display the same diagnosis panel used by local tunnel/forward diagnosis.</li><li>If provider returns unsupported command, show a compatibility warning instead of marking the local node broken.</li></ul></li><li><p>Capability handshake:</p><ul><li>Add optional capability detection on <code>/federation/connect</code>.</li><li>Expected new optional fields: <ul><li><code>protocolVersion</code></li><li><code>features</code></li><li><code>runtimeModes</code></li><li><code>supportsNftables</code></li><li><code>supportsWGPath</code></li><li><code>supportsTLSInbound</code></li></ul></li><li>If missing, assume Sagit-chu-compatible baseline: <ul><li><code>features = [&quot;gost_tunnel&quot;, &quot;port_forward&quot;, &quot;runtime_reserve&quot;, &quot;runtime_apply&quot;, &quot;runtime_release&quot;, &quot;runtime_diagnose&quot;]</code></li><li><code>supportsWGPath = false</code></li><li><code>supportsTLSInbound = false</code></li></ul></li></ul></li><li><p>Permission model:</p><ul><li>Share creation and share management should remain admin-only in <code>flvxt2</code>.</li><li>Imported federated nodes may be assigned to groups/users according to existing group permission rules.</li><li>Ordinary users must not be able to create provider shares or import arbitrary remote shares unless explicitly enabled by commercial policy.</li><li>WG Path remains admin-only even if a remote panel advertises WG support.</li></ul></li><li><p>Failure behavior:</p></li></ol><ul><li>If remote reservation succeeds but local tunnel creation fails, release the remote reservation immediately.</li><li>If remote apply fails after reservation, release and surface the provider error.</li><li>If provider is unreachable during update, do not delete old working local binding until rollback is decided.</li></ul><p>Recommended merge strategy:</p><ul><li>Treat Sagit-chu compatibility as a protocol adapter, not as a wholesale file copy.</li><li>Keep <code>flvxt2</code> data model as the authoritative local model.</li><li>Add a <code>federation provider capability</code> normalization layer in <code>go-backend/internal/http/client/federation.go</code>.</li><li>Add contract tests with two simulated providers: <ul><li>baseline Sagit-chu-compatible provider with no capability fields</li><li>flvxt2 provider with extended capability fields</li></ul></li><li>Keep UI labels as “面板共享 / Panel Peering”, but show imported provider type: <ul><li><code>FLVX compatible</code></li><li><code>Sagit-chu compatible</code></li><li><code>Unknown legacy</code></li></ul></li><li>Do not expose WG/TLS deployment buttons on imported Sagit-chu remote nodes.</li></ul><h3 id="auth-and-session" tabindex="-1">Auth And Session <a class="header-anchor" href="#auth-and-session" aria-label="Permalink to &quot;Auth And Session&quot;">​</a></h3><ul><li><code>go-backend/internal/http/middleware/auth.go</code></li><li><code>go-backend/internal/http/middleware/cors.go</code></li><li><code>go-backend/internal/auth/jwt.go</code></li><li><code>vite-frontend/src/api/index.ts</code></li><li><code>vite-frontend/src/api/network.ts</code></li><li><code>vite-frontend/src/utils/auth.ts</code></li><li><code>vite-frontend/src/utils/jwt.ts</code></li><li><code>vite-frontend/src/utils/logout.ts</code></li><li><code>vite-frontend/src/utils/session.ts</code></li></ul><p>Why adaptation is needed:</p><ul><li><code>flvxt2</code> now uses HttpOnly cookie as the main browser auth path.</li><li>Upstream still expects token-style flows in several places.</li></ul><p>Recommended merge strategy:</p><ul><li>Only import tests or narrowly scoped validation improvements.</li><li>Do not replace cookie/session behavior.</li></ul><h3 id="websocket-and-agent-runtime" tabindex="-1">WebSocket And Agent Runtime <a class="header-anchor" href="#websocket-and-agent-runtime" aria-label="Permalink to &quot;WebSocket And Agent Runtime&quot;">​</a></h3><ul><li><code>go-backend/internal/ws/server.go</code></li><li><code>go-gost/x/socket/websocket_reporter.go</code></li><li><code>go-gost/x/socket/websocket_reporter_test.go</code></li><li><code>go-gost/x/socket/service.go</code></li><li><code>go-gost/x/socket/chain.go</code></li><li><code>go-gost/x/socket/limiter.go</code></li></ul><p>Why adaptation is needed:</p><ul><li><code>flvxt2</code> added <code>ApplyCoreConfig</code>, WireGuard config application, cookie fallback for panel WebSocket auth, and node deployment commands.</li><li>Upstream may contain stability fixes, but direct replacement could reintroduce <code>未知命令类型: ApplyCoreConfig</code>.</li></ul><p>Recommended merge strategy:</p><ul><li>Compare command type registry and message handlers first.</li><li>Keep all <code>ApplyCoreConfig</code>, WG, TLS deployment, and node identity handling.</li><li>Cherry-pick reconnect, limiter, status, and telemetry fixes.</li></ul><h3 id="go-gost-network-core" tabindex="-1">go-gost Network Core <a class="header-anchor" href="#go-gost-network-core" aria-label="Permalink to &quot;go-gost Network Core&quot;">​</a></h3><ul><li><code>go-gost/config.go</code></li><li><code>go-gost/main.go</code></li><li><code>go-gost/program.go</code></li><li><code>go-gost/x/config/config.go</code></li><li><code>go-gost/x/config/parsing/service/parse.go</code></li><li><code>go-gost/x/config/persist.go</code></li><li><code>go-gost/x/handler/forward/local/handler.go</code></li><li><code>go-gost/x/handler/forward/local/metadata.go</code></li><li><code>go-gost/x/internal/net/udp/listener.go</code></li><li><code>go-gost/x/listener/udp/listener.go</code></li><li><code>go-gost/x/listener/udp/metadata.go</code></li><li><code>go-gost/x/service/global_traffic_manager.go</code></li><li><code>go-gost/x/service/service.go</code></li></ul><p>Why adaptation is needed:</p><ul><li>These are central traffic-path files.</li><li>Upstream has useful UDP, retry, proxy protocol, and traffic manager changes.</li><li><code>flvxt2</code> has agent-specific reporting, WG, nftables socket handlers, and deployment assumptions.</li></ul><p>Recommended merge strategy:</p><ul><li>Port tests first.</li><li>Then port one protocol/runtime area at a time with performance checks.</li></ul><h3 id="frontend-ui-and-layout" tabindex="-1">Frontend UI And Layout <a class="header-anchor" href="#frontend-ui-and-layout" aria-label="Permalink to &quot;Frontend UI And Layout&quot;">​</a></h3><ul><li><code>vite-frontend/src/layouts/admin.tsx</code></li><li><code>vite-frontend/src/layouts/default.tsx</code></li><li><code>vite-frontend/src/pages/dashboard.tsx</code></li><li><code>vite-frontend/src/pages/node.tsx</code></li><li><code>vite-frontend/src/pages/tunnel.tsx</code></li><li><code>vite-frontend/src/pages/forward.tsx</code></li><li><code>vite-frontend/src/pages/config.tsx</code></li><li><code>vite-frontend/src/components/navbar.tsx</code></li><li><code>vite-frontend/src/components/version-footer.tsx</code></li><li><code>vite-frontend/src/styles/globals.css</code></li><li><code>vite-frontend/src/styles/tailwind-theme.pcss</code></li></ul><p>Why adaptation is needed:</p><ul><li><code>flvxt2</code> has custom modern glass UI, commercial visibility rules, TLS inside node menus, WG controls, shop tabs, and branding restrictions.</li><li>Upstream UI changes can be useful, but direct replacement would regress current product behavior.</li></ul><p>Recommended merge strategy:</p><ul><li>Only cherry-pick bug fixes and ergonomic improvements.</li><li>Do not import upstream navigation, branding, or layout wholesale.</li></ul><h2 id="not-migratable" tabindex="-1">Not Migratable <a class="header-anchor" href="#not-migratable" aria-label="Permalink to &quot;Not Migratable&quot;">​</a></h2><p>These files should not be copied from upstream into <code>flvxt2</code>, because they would break repository ownership, licensing, release assets, branding, commercial behavior, or custom product logic.</p><h3 id="installation-release-and-image-ownership" tabindex="-1">Installation, Release, And Image Ownership <a class="header-anchor" href="#installation-release-and-image-ownership" aria-label="Permalink to &quot;Installation, Release, And Image Ownership&quot;">​</a></h3><ul><li><code>install.sh</code></li><li><code>panel_install.sh</code></li><li><code>docker-compose-v4.yml</code></li><li><code>docker-compose-v6.yml</code></li><li><code>.github/workflows/*</code></li><li><code>go-backend/internal/http/handler/upgrade.go</code></li><li><code>go-backend/internal/http/handler/system_upgrade.go</code></li><li><code>vite-frontend/src/config/site.ts</code></li><li><code>vite-frontend/src/components/version-footer.tsx</code></li></ul><p>Reason:</p><ul><li>Upstream points to <code>Sagit-chu/flvx</code>, <code>Sagit-chu/flux-panel</code>, and <code>ghcr.io/sagit-chu/...</code>.</li><li><code>flvxt2</code> must remain on <code>iKeilo/FLVXR2</code> and <code>ghcr.io/ikeilo/...</code>.</li><li>Replacing these would recreate the earlier wrong-project installation problem.</li></ul><p>Allowed action:</p><ul><li>Manually inspect upstream for installer bug fixes only.</li><li>Keep all repo/image/version ownership values from <code>flvxt2</code>.</li></ul><h3 id="commercial-license-and-business-modules" tabindex="-1">Commercial License And Business Modules <a class="header-anchor" href="#commercial-license-and-business-modules" aria-label="Permalink to &quot;Commercial License And Business Modules&quot;">​</a></h3><p>Do not replace or backport upstream over these target-side files:</p><ul><li><code>go-backend/internal/license/defaults.go</code></li><li><code>go-backend/internal/license/domain.go</code></li><li><code>go-backend/internal/middleware/license_check.go</code></li><li><code>go-backend/internal/http/middleware/license_guard.go</code></li><li><code>go-backend/internal/http/middleware/trial_guard.go</code></li><li><code>go-backend/internal/http/handler/license_config.go</code></li><li><code>go-backend/internal/http/handler/license_info.go</code></li><li><code>go-backend/internal/http/handler/license_tier.go</code></li><li><code>go-backend/internal/http/handler/license_commercial.go</code></li><li><code>go-backend/internal/http/handler/license_transfer.go</code></li><li><code>go-backend/internal/http/handler/billing.go</code></li><li><code>go-backend/internal/http/handler/product.go</code></li><li><code>go-backend/internal/http/handler/order.go</code></li><li><code>go-backend/internal/http/handler/payment.go</code></li><li><code>go-backend/internal/payment/*</code></li><li><code>go-backend/internal/store/model/billing.go</code></li><li><code>go-backend/internal/store/model/order.go</code></li><li><code>go-backend/internal/store/model/product.go</code></li><li><code>go-backend/internal/store/model/payment_config.go</code></li><li><code>go-backend/internal/store/repo/repository_billing.go</code></li><li><code>go-backend/internal/store/repo/repository_order.go</code></li><li><code>go-backend/internal/store/repo/repository_payment_config.go</code></li></ul><p>Reason:</p><ul><li>These are <code>flvxt2</code> commercial product layers.</li><li>Upstream does not have equivalent commercial semantics.</li></ul><h3 id="node-deployment-tls-and-inbound-management" tabindex="-1">Node Deployment, TLS, And Inbound Management <a class="header-anchor" href="#node-deployment-tls-and-inbound-management" aria-label="Permalink to &quot;Node Deployment, TLS, And Inbound Management&quot;">​</a></h3><p>Do not replace these target-side files with upstream equivalents or remove them during merge:</p><ul><li><code>go-backend/internal/http/handler/node_deploy.go</code></li><li><code>go-backend/internal/store/repo/repository_node_deploy.go</code></li><li><code>vite-frontend/src/pages/node/node-deploy-modal.tsx</code></li><li><code>vite-frontend/src/pages/tls.tsx</code></li><li><code>vite-frontend/src/api/types.ts</code> TLS/deploy sections</li></ul><p>Reason:</p><ul><li>These implement S-UI-inspired TLS/Reality template and node deployment behavior.</li><li>Upstream does not model this feature set.</li></ul><h3 id="wg-path-product-surface" tabindex="-1">WG Path Product Surface <a class="header-anchor" href="#wg-path-product-surface" aria-label="Permalink to &quot;WG Path Product Surface&quot;">​</a></h3><p>Do not replace these target-side files with upstream:</p><ul><li><code>go-backend/internal/http/handler/wg_path.go</code></li><li><code>go-backend/internal/http/handler/wg_path_test.go</code></li><li><code>go-backend/internal/store/repo/repository_wg_path.go</code></li><li><code>go-gost/x/socket/wireguard_handler.go</code></li><li><code>go-gost/x/socket/wireguard_handler_stub.go</code></li><li><code>vite-frontend/src/pages/tunnel/wg-path-manager.tsx</code></li><li><code>vite-frontend/src/pages/forward.tsx</code> WG mode sections</li><li><code>vite-frontend/src/pages/tunnel.tsx</code> WG switch/manager sections</li></ul><p>Reason:</p><ul><li>WG Path is a <code>flvxt2</code> feature and is admin-gated.</li><li>Upstream does not contain the same model.</li></ul><h3 id="generated-or-binary-artifacts" tabindex="-1">Generated Or Binary Artifacts <a class="header-anchor" href="#generated-or-binary-artifacts" aria-label="Permalink to &quot;Generated Or Binary Artifacts&quot;">​</a></h3><p>Do not migrate these from either side:</p><ul><li><code>docs/assets/*</code></li><li><code>docs/*.html</code></li><li><code>go-backend/cmd/paneld/paneld</code></li><li><code>go-gost/flux_agent</code></li><li><code>go-gost/gost-linux-amd64</code></li><li><code>vite-frontend/dist/*</code></li></ul><p>Reason:</p><ul><li>These are generated build artifacts or binaries.</li><li>They should be rebuilt by CI/release workflows.</li></ul><h2 id="recommended-execution-order" tabindex="-1">Recommended Execution Order <a class="header-anchor" href="#recommended-execution-order" aria-label="Permalink to &quot;Recommended Execution Order&quot;">​</a></h2><ol><li>Import direct test files first.</li><li>Port low-risk backend utilities: <code>security_utils.go</code>, password helpers, config policy helpers.</li><li>Port nftables runtime as an isolated package behind a feature boundary.</li><li>Add Panel Peering compatibility adapter and tests for Sagit-chu baseline providers.</li><li>Port tunnel probe/best-exit fixes and expose them to WG diagnostics.</li><li>Port forward-mode fixes while preserving <code>wg_path</code> and admin-only restrictions.</li><li>Re-run backend tests, frontend build, and <code>go-gost</code> build.</li><li>Deploy to test server and verify: <ul><li>normal tunnel creation</li><li>nftables mode</li><li>WG Path creation/edit/diagnosis</li><li>non-admin cannot create/use WG</li><li>login/logout still uses HttpOnly cookie</li><li>install scripts still resolve <code>iKeilo/FLVXR2</code></li><li>imported Sagit-chu panel share can reserve/apply/release a GOST tunnel</li><li>imported Sagit-chu panel share does not expose WG/TLS deployment-only actions</li></ul></li></ol>',112)])])}const m=o(a,[["render",n]]);export{u as __pageData,m as default};
